select A.write_year, A.doc_type, A.doc_no, A.comp_id ,D.legal_id, D.legal_nm, D.legal_cd, A.confirmed_yn, A.confirmed_dt, A.use_yn, B.minor_nm as div_fg, A.revision_at, A.revision_by ,A.created_at, A.created_by, A.updated_at, A.updated_by, 'U' as cmd , (case when c.approverCnd > 0 then 'Y' when c.reviewerCnd > 0 then 'I' when c.writerCnd > 0 then 'W' else 'C' end) as approval_status from esg.tb_legal_manage A left join esg.tb_common_d B on a.div_fg =b.minor_cd and b.major_cd = 'C0015' left join ( select target_type, target_id, count(CASE WHEN param = 'writer' and signature is not null THEN 1 END) AS writerCnd, count(CASE WHEN param = 'reviewer' and signature is not null THEN 1 END) AS reviewerCnd, count(CASE WHEN param = 'approver' and signature is not null THEN 1 END) AS approverCnd from esg.tb_approval_info where target_type ='LGM' group by target_type, target_id ) C on C.target_type = a.doc_type and C.target_id = a.write_year||a.doc_no left join esg.tb_legal_manage_type D on D.legal_id = A.legal_id and D.comp_id = A.comp_id where A.comp_id = #{compId}
and A.write_year = #{writeYear}
and A.doc_type = #{docType}
ORDER BY A.write_year DESC, A.use_yn DESC, A.created_at DESC

select A.write_year, A.doc_type, A.doc_no, A.comp_id ,A.legal_id, D.legal_nm, A.use_yn, B.minor_nm as div_fg, A.revision_at, A.revision_by ,A.created_at, A.created_by, A.updated_at, A.updated_by, 'U' as cmd, A.confirmed_yn , (case when c.approverCnd > 0 then 'Y' when c.reviewerCnd > 0 then 'I' when c.writerCnd > 0 then 'W' else 'C' end) as approval_status from esg.tb_legal_manage A left join esg.tb_common_d B on a.div_fg =b.minor_cd and b.major_cd = 'C0015' left join ( select target_type, target_id, count(CASE WHEN param = 'writer' and signature is not null THEN 1 END) AS writerCnd, count(CASE WHEN param = 'reviewer' and signature is not null THEN 1 END) AS reviewerCnd, count(CASE WHEN param = 'approver' and signature is not null THEN 1 END) AS approverCnd from esg.tb_approval_info where target_type ='LGM' group by target_type, target_id ) C on C.target_type = a.doc_type and C.target_id = a.write_year||a.doc_no left join esg.tb_legal_manage_type D on D.legal_id = A.legal_id and D.comp_id = A.comp_id where A.write_year = #{writeYear} and A.comp_id = #{compId}
and A.doc_type = #{docType}
ORDER BY A.write_year DESC, A.use_yn DESC, A.created_at DESC

        select   A.write_year, A.doc_type, A.doc_no, A.comp_id, A.confirmed_yn
	  			,A.legal_id, B.legal_nm, B.legal_cd, A.use_yn, A.div_fg, A.revision_at, A.revision_by
	  			,A.created_at, A.created_by, A.updated_at, A.updated_by, 'U' as cmd 
	  	from esg.tb_legal_manage A
	  	left join esg.tb_legal_manage_type B on B.legal_id = A.legal_id and B.comp_id = A.comp_id
	  	where A.write_year = #{writeYear}
  		  and A.comp_id = #{compId}


	  		and A.doc_no = #{docNo}



	  		and A.doc_type = #{docType}


        ORDER BY A.use_yn DESC, A.created_at DESC

        select A.write_year, A.doc_type, A.doc_no, A.doc_seq, A.article_title, A.article_content, A.ref_id, C.legal_id, C.legal_nm
			, A.remark_dc, A.revision_at, A.use_yn, A.created_at, 'U' as cmd
			from esg.tb_legal_manage_detail A
			left join esg.tb_legal_manage B on a.write_year = b.write_year and a.doc_type = b.doc_type and a.doc_no = b.doc_no
			left join esg.tb_legal_manage_type C on C.legal_id = B.legal_id and C.comp_id = B.comp_id
			where A.write_year = #{writeYear} and C.comp_id = #{compId}

		  		and A.doc_no = #{docNo}



	  			and A.doc_type = #{docType}



		  	ORDER BY A.use_yn DESC, CAST(A.doc_seq AS INTEGER) DESC

