    		update esg.tb_legal_manage
    		set
    			legal_id = #{legalId},
    			legal_nm = #{legalNm},
    			div_fg = #{divFg},
    			use_yn = #{useYn},
    			revision_at = TO_TIMESTAMP(#{revisionAt}, 'YYYYMMDD HH24:MI:SS'),
    			updated_at = now(),
    			updated_by = #{createdBy}
   			WHERE comp_id = #{compId}
	            AND write_year = #{writeYear}
	            AND doc_type = #{docType}
	            AND doc_no = #{docNo}

mapper.insert:

    		insert into esg.tb_legal_manage_detail (write_year, doc_type, doc_no, doc_seq, article_title, article_content, remark_dc, revision_at, created_at, created_by, updated_at, updated_by, use_yn, ref_id)
								 values(#{writeYear} , #{docType}, #{docNo},

        						 (
          							  	SELECT
											(COALESCE(MAX(doc_seq::INTEGER), 0) + 1)::TEXT AS docSeq
									    FROM esg.tb_legal_manage_detail
										WHERE write_year = #{writeYear}
											AND doc_type = #{docType}
											AND doc_no   = #{docNo}
        						 ),
								 #{articleTitle}, #{articleContent}, #{remarkDc}, TO_TIMESTAMP(#{revisionAt}, 'YYYYMMDD HH24:MI:SS'), now(), #{createdBy}, now(), #{createdBy}, #{useYn}, #{refId})



    		update esg.tb_legal_manage_detail
    		set
    			article_title = #{articleTitle},
    			article_content = #{articleContent},
				remark_dc = #{remarkDc},
    			revision_at = TO_TIMESTAMP(#{revisionAt}, 'YYYYMMDD HH24:MI:SS'),
    			updated_at = now(),
    			updated_by = #{createdBy},
    			use_yn = #{useYn}
   			WHERE write_year = #{writeYear}
	            AND doc_type = #{docType}
	            AND doc_no = #{docNo}
	            AND doc_seq = #{docSeq}

