UPDATE esg.tb_legal_manage
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
    AND write_year = #{writeYear}
    AND doc_type = #{docType}
    AND doc_no = #{docNo}

UPDATE esg.tb_legal_manage_detail
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE doc_no = #{docNo}
    AND write_year = #{writeYear}
    AND doc_type = #{docType}
    And doc_seq = #{docSeq}

