        SELECT
			LPAD((COALESCE(MAX(doc_no::INTEGER), 0) + 1)::TEXT, 5, '0') AS docNo
	    FROM esg.tb_legal_manage
		WHERE write_year = #{writeYear}
			AND doc_type = #{docType}

        select count(legal_nm) as cnt
		from esg.tb_legal_manage 
		WHERE doc_type = #{docType}
			AND legal_nm = #{legalNm}

        select legal_id, div_fg
		from esg.tb_legal_manage 
