    and   a.write_year = #{writeYear}
    and   a.doc_type = #{docType}
    and   a.doc_no = #{docNo}  
     and   B.doc_seq IN   

	        #{gridValue}



  		and B.use_yn = 'Y'	


	),

	data_count AS (
	    SELECT COUNT(*) AS row_count FROM original_data
	)

	SELECT * FROM original_data

	order by doc_seq DESC;

